import { clientId, clientSecret, redirectUri } from './constants';
import axios from 'axios';

const authUrl = `https://accounts.google.com/o/oauth2/auth?response_type=code&redirect_uri=${redirectUri}&client_id=${clientId}&scope=email+profile`;

const getToken = async (authCode) => {
  const headers = {
    method: 'POST',
    headers: {
      'Content-Type': 'application/x-www-form-urlencoded'
    }
  };

  const body = `grant_type=authorization_code&code=${authCode}&redirect_uri=${redirectUri}&client_id=${clientId}&client_secret=${clientSecret}`;

  try {
    const response = await fetch(`https://accounts.google.com/o/oauth2/token`, headers);
    const data = await response.json();
    return data.access_token;
  } catch (error) {
    console.error(error);
  }
};

const login = async () => {
  // Open the authorization URL in a new tab/window
  window.location.href = authUrl;

  try {
    const queryStringParams = new URLSearchParams(window.location.search);
    const code = queryStringParams.get('code');
    if (code) {
      const token = await getToken(code);
      localStorage.setItem('token', token);
    }
  } catch (error) {
    console.error(error);
  }

  // Navigate back to the app
  setTimeout(() => window.history.go(-1), 1000);
};

